"use strict";parserFactory.register("ffxs8.com",()=>new Ffxs8Parser);class Ffxs8Parser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("div.catalog");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector("div.content")}findChapterTitle(e){return e.querySelector("div.article h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.cover")}async fetchChapter(e){return(await HttpClient.wrapFetch(e,this.makeOptions())).responseXML}makeOptions(){return{makeTextDecoder:()=>new TextDecoder("gb2312")}}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.descInfo")]}}